#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int allOdd = 1;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x % 2 == 0) allOdd = 0;
        }
        printf("%s\n", allOdd ? "YES" : "NO");
    }
    return 0;
}

