#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        all_odd = True
        for _ in range(N):
            x = int(next(it))
            if x % 2 == 0:
                all_odd = False
        out.append('YES' if all_odd else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

